import React, { useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import { InAppBilling } from 'react-native-iap';

const itemSkus = Platform.select({
  ios: ['com.example.product1', 'com.example.product2'],
  android: ['android.test.purchased', 'product.android.test.subscription']
});

export default function PaymentModule() {
  const [purchaseData, setPurchaseData] = useState(null);
  const [loading, setLoading] = useState(false);

  InAppBilling.init()
    .then(() => console.log('In-App Billing module is initialized'))
    .catch(err => console.error('init error', err));

  const requestPurchase = async (sku) => {
    try {
      setLoading(true);
      const purchaseResult = await InAppBilling.requestPurchase({ sku, andDangerouslyIgnoreDuplicates: true });
      setPurchaseData(purchaseResult);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      {itemSkus.map(sku => (
        <Button key={sku} title={`Buy ${sku}`} onPress={() => requestPurchase(sku)} disabled={loading} />
      ))}
      {purchaseData && (
        <Text style={styles.text}>Purchase successful: {JSON.stringify(purchaseData)}</Text>
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  text: {
    marginTop: 20,
    fontSize: 16,
    textAlign: 'center',
  },
});